async (params, browser) => {
  // Search Google Flights
  await browser.open(`https://www.google.com/travel/flights?q=${params.from}+to+${params.to}`)

  // Wait for flight results
  await browser.waitForSelector('li.pIav2d', 20000)

  // Let page render
  await browser.wait(3000)

  // Open date grid view
  const open_date_grid = await browser.evaluate(`const dateGridBtn = document.querySelector('button[aria-label*="Date grid"], button[aria-label*="date grid"], div[data-flt-ve="date_grid"] button, button[jsaction*="date_grid"]'); if (dateGridBtn) { dateGridBtn.click(); return { clicked: true, type: 'date_grid' }; } const priceGraphBtn = document.querySelector('button[aria-label*="Price graph"], button[aria-label*="price graph"]'); if (priceGraphBtn) { priceGraphBtn.click(); return { clicked: true, type: 'price_graph' }; } return { clicked: false }`)

  // Wait for date grid to load
  await browser.wait(4000)

  // Scroll to see date grid
  await browser.scroll({ direction: 'down', amount: 600 })

  await browser.wait(2000)

  // Extract cheapest date combinations
  const cheapest_dates = await browser.evaluate(`const dateEntries = []; const gridCells = document.querySelectorAll('td[data-value], div[class*="date-grid"] td, div[class*="price-grid"] td, table td[role="button"], div.JRwjBf td'); gridCells.forEach((cell, i) => { if (i >= 90) return; const label = cell.getAttribute('aria-label') || ''; const value = cell.getAttribute('data-value') || ''; const priceEl = cell.querySelector('div, span'); const text = cell.textContent.trim(); if (text && text.match(/\d/)) { dateEntries.push({ date: value || label.split(',')[0] || '', price: priceEl ? priceEl.textContent.trim() : text, aria_label: label, is_cheapest: cell.classList.contains('cheapest') || cell.querySelector('[class*="cheapest"], [class*="lowest"]') !== null }); } }); const calendarBtns = document.querySelectorAll('button[aria-label*="$"], button[aria-label*="EUR"], button[aria-label*="GBP"], div[class*="calendar"] button[data-iso]'); calendarBtns.forEach((btn, i) => { if (i >= 60) return; const label = btn.getAttribute('aria-label') || ''; const iso = btn.getAttribute('data-iso') || ''; if (label) { dateEntries.push({ date: iso || label, price: label, is_cheapest: false }); } }); const cheapestEl = document.querySelector('div[class*="cheapest"], div[class*="lowest-price"], div.CQYfx'); const tipEl = document.querySelector('div[class*="tip"], div[class*="advice"], div[class*="insight"]'); dateEntries.sort((a, b) => { const pa = parseInt((a.price || '').replace(/[^0-9]/g, '')) || 99999; const pb = parseInt((b.price || '').replace(/[^0-9]/g, '')) || 99999; return pa - pb; }); return { from: params.from, to: params.to, date_count: dateEntries.length, cheapest_dates: dateEntries.slice(0, 20), cheapest_highlight: cheapestEl ? cheapestEl.textContent.trim() : '', travel_tip: tipEl ? tipEl.textContent.trim() : '', url: window.location.href }`)

  return cheapest_dates
}
